-- Radar demo seed for remote project.
-- Password for every seeded account is 123456.
begin;

truncate table
  public.report_events,
  public.notifications,
  public.matches,
  public.claims,
  public.matching_jobs,
  public.maintenance_incidents,
  public.lost_items,
  public.reports,
  public.technicians,
  public.profiles,
  public.campus_zones,
  public.system_settings
restart identity cascade;

delete from auth.users;
create temporary table seed_users (id uuid primary key, email text not null, full_name text not null, app_role public.user_role not null) on commit drop;

  id,
  instance_id,
  aud,
  role,
  email,
  encrypted_password,
  email_confirmed_at,
  confirmation_token,
  recovery_token,
  email_change_token_new,
  email_change,
  phone_change,
  phone_change_token,
  email_change_token_current,
  reauthentication_token,
  raw_app_meta_data,
  raw_user_meta_data,
  created_at,
  updated_at,
  is_anonymous
)
select
  id,
  '00000000-0000-0000-0000-000000000000'::uuid,
  'authenticated',
  'authenticated',
  email,
  crypt('123456', gen_salt('bf', 10)),
  now(),
  '',
  '',
  '',
  '',
  '',
  '',
  '',
  '',
  jsonb_build_object('provider', 'email', 'providers', jsonb_build_array('email')),
  jsonb_build_object('full_name', full_name, 'name', full_name, 'email_verified', true),
  now(),
  now(),
  false
from seed_users;


select gen_random_uuid(), id::text, id, jsonb_build_object('sub', id::text, 'email', email, 'email_verified', true, 'phone_verified', false), 'email', null, now(), now()
from seed_users;


select id, email, full_name, app_role, null, now(), now()
from seed_users
on conflict (id) do update set
  email = excluded.email,
  full_name = excluded.full_name,
  role = excluded.role,
  avatar_url = excluded.avatar_url,
  updated_at = excluded.updated_at;

