select 'profiles' as table_name, count(*) from public.profiles union all select 'technicians', count(*) from public.technicians union all select 'campus_zones', count(*) from public.campus_zones union all select 'reports', count(*) from public.reports union all select 'maintenance_incidents', count(*) from public.maintenance_incidents union all select 'lost_items', count(*) from public.lost_items union all select 'claims', count(*) from public.claims union all select 'matches', count(*) from public.matches union all select 'matching_jobs', count(*) from public.matching_jobs union all select 'report_events', count(*) from public.report_events union all select 'notifications', count(*) from public.notifications order by table_name;
